        project_name = match.group(1)
        stars = int(match.group(2).replace(',', ''))
        project_stars[project_name] = stars

print('Total latest release packages:', len(latest_packages))
print('Total projects with stars:', len(project_stars))
print('Sample project stars:', list(project_stars.items())[:5])

# Map packages to projects and get stars
