        if mapping['Name'] == pkg['name'] and mapping['Version'] == pkg['version']:
            project_name = mapping['ProjectName']
            if project_name in project_stars:
                results.append({
                    'Package': pkg['name'],
                    'Version': pkg['version'],
                    'Stars': project_stars[project_name]
                })

# Sort by stars and get top 5
top5 = sorted(results, key=lambda x: x['Stars'], reverse=True)[:5]

print('Top 5 packages:', json.dumps(top5, indent=2))"}

