# Read data files
with open('var_functions.query_db:16', 'r') as f:
    packages = json.load(f)

with open('var_functions.query_db:26', 'r') as f:
    mappings = json.load(f)

with open('var_functions.query_db:28', 'r') as f:
    projects = json.load(f)

# Step 1: Find latest release version for each package
latest = {}
for p in packages:
    try:
        vinfo = json.loads(p['VersionInfo'])
        if vinfo.get('IsRelease'):
            name = p['Name']
            ordinal = vinfo.get('Ordinal', 0)
            if name not in latest or ordinal > latest[name]['ordinal']:
                latest[name] = {
                    'version': p['Version'],
                    'ordinal': ordinal
                }
    except:
        pass

# Step 2: Extract stars from project descriptions
stars = {}
for proj in projects:
    info = proj['Project_Information']
    m = re.search(r'([\w-]+/[\w-]+).*?(\d+|[\d,]+)\s+stars', info)
    if m:
        proj_name = m.group(1)
        star_count = int(m.group(2).replace(',', ''))
        stars[proj_name] = star_count

# Step 3: Match packages to projects
results = []
for m in mappings:
    pname = m['Name']
    pver = m['Version']
    proj_name = m['ProjectName']

    if pname in latest and pver == latest[pname]['version'] and proj_name in stars:
        results.append({
            'Package': pname,
            'Version': pver,
            'Stars': stars[proj_name]
        })

# Step 4: Get top 5 by stars
top5 = sorted(results, key=lambda x: x['Stars'], reverse=True)[:5]

# Print in required format
print('__RESULT__:')
print(json.dumps(top5))"}

