    try:
        vinfo = json.loads(p['VersionInfo'])
        if vinfo.get('IsRelease'):
            name = p['Name']
            ordinal = vinfo.get('Ordinal', 0)
            if name not in latest or ordinal > latest[name]['ordinal']:
                latest[name] = {'version': p['Version'], 'ordinal': ordinal}
    except:
        pass

# Step 2: Build project stars mapping
stars = {}
for proj in projects:
    info = proj['Project_Information']
    m = re.search(r'([\w-]+/[\w-]+).*?(\d+|[\d,]+)\s+stars', info)
    if m:
        stars[m.group(1)] = int(m.group(2).replace(',',''))

# Step 3: Match packages to projects
results = []
for m in mappings:
    if m['Name'] in latest and m['Version'] == latest[m['Name']]['version']:
        if m['ProjectName'] in stars:
            results.append({'Package': m['Name'], 'Version': m['Version'], 'Stars': stars[m['ProjectName']]})

# Sort and get top 5 without duplicates
top5 = []
seen = set()
for r in sorted(results, key=lambda x: x['Stars'], reverse=True):
    if r['Package'] not in seen:
        top5.append(r)
        seen.add(r['Package'])
    if len(top5) >= 5:
        break

# Output
print('__RESULT__:')
print(json.dumps(top5))"}

