# Load data from stored file paths
pkg_data = json.load(open(locals()['var_functions.query_db:16'], 'r'))
map_data = json.load(open(locals()['var_functions.query_db:26'], 'r'))
proj_data = json.load(open(locals()['var_functions.query_db:28'], 'r'))

# Step 1: Find latest release version for each NPM package
latest_pkg = {}
for item in pkg_data:
    try:
        vinfo = json.loads(item['VersionInfo'])
        if vinfo.get('IsRelease'):
            name = item['Name']
            ordinal = vinfo.get('Ordinal', 0)
            if name not in latest_pkg or ordinal > latest_pkg[name]['ordinal']:
                latest_pkg[name] = {
                    'version': item['Version'],
                    'ordinal': ordinal
                }
    except:
        pass

# Step 2: Extract GitHub stars from project information
project_stars = {}
for proj in proj_data:
    info = proj['Project_Information']
    # Match pattern: "owner/repo ... X stars"
    match = re.search(r'([\w-]+/[\w-]+).*?(\d+|[\d,]+)\s+stars', info)
    if match:
        project_name = match.group(1)
        stars = int(match.group(2).replace(',', ''))
        project_stars[project_name] = stars

# Step 3: Map packages to projects and collect stars for latest versions
package_ranking = []
for mapping in map_data:
    pkg_name = mapping['Name']
    pkg_version = mapping['Version']
    project_name = mapping['ProjectName']

    # Only consider package if it's the latest release version
    if pkg_name in latest_pkg and pkg_version == latest_pkg[pkg_name]['version']:
        if project_name in project_stars:
            package_ranking.append({
                'Package': pkg_name,
                'Version': pkg_version,
                'Stars': project_stars[project_name]
            })

# Step 4: Remove duplicates and sort to get top 5
unique_packages = {}
for pkg in package_ranking:
    if pkg['Package'] not in unique_packages or pkg['Stars'] > unique_packages[pkg['Package']]['Stars']:
        unique_packages[pkg['Package']] = pkg

# Sort by stars descending and take top 5
top_5 = sorted(unique_packages.values(), key=lambda x: x['Stars'], reverse=True)[:5]

# Format final answer
print('__RESULT__:')
print(json.dumps(top_5))"}
